function normalizeNewlines(s) {
  return String(s || '')
    .replace(/\\n/g, '\n')          // буквальные \n -> реальные
    .replace(/<br\s*\/?>/gi, '\n'); // <br> -> \n
}

function unescapeAllowedEntities(s) {
  // если на вход прилетает &lt;blockquote&gt;...&lt;/blockquote&gt;
  // возвращаем нормальные теги (только для разрешённых!)
  return s
    .replace(/&lt;(\/?)(blockquote|b|strong|i|em|u|ins|s|strike|del|code|pre|a)\b/gi, '<$1$2')
    .replace(/&gt;/g, '>');
}

function convertMarkdownBlockquotesToHtml(text) {
  // text уже может содержать HTML теги — поэтому обрабатываем построчно
  const lines = text.split('\n');
  const out = [];
  let q = [];

  const flush = () => {
    if (!q.length) return;
    out.push(`<blockquote>${q.join('\n')}</blockquote>`);
    q = [];
  };

  for (const line of lines) {
    const m = line.match(/^\s*>\s?(.*)$/); // markdown quote
    if (m) q.push(m[1]);
    else { flush(); out.push(line); }
  }
  flush();

  return out.join('\n');
}

function stripUnsafeTags(html) {
  // удаляем все теги кроме разрешённых Телеграмом HTML
  return html.replace(/<(?!\/?(blockquote|b|strong|i|em|u|ins|s|strike|del|code|pre|a)\b)[^>]*>/gi, '');
}

function sanitizeTelegramHtml(input) {
  let t = normalizeNewlines(input);

  // ВАЖНО: сначала разэкраним разрешённые теги, если они пришли как &lt;...&gt;
  t = unescapeAllowedEntities(t);

  // markdown   и   (если нужно — можешь расширить)
  t = t.replace(/\*\*(.*?)\*\*/g, '<b>$1</b>');
  t = t.replace(/__(.*?)__/g, '<u>$1</u>');

  // markdown quotes -> <blockquote>
  t = convertMarkdownBlockquotesToHtml(t);

  // вычищаем всё лишнее, оставляем только то, что Telegram понимает
  t = stripUnsafeTags(t);

  // чуть чистим пробелы
  t = t.replace(/[ \t]+\n/g, '\n').trim();

  return t;
}

// --- n8n part ---
const inputData = $input.first().json;
const originalText = inputData.assistant_text || '';

const cleanText = sanitizeTelegramHtml(originalText);

return [
  {
    json: {
      ...inputData,
      output: cleanText,
    },
  },
];

const telegramData = $('Telegram User Message').first().json;
const chatId = telegramData.message.chat.id;
const telegramMsg = telegramData.message;

let userText;
if (telegramMsg.voice) {
  userText = $('Transcribe audio').first().json.text;
} else {
  userText = telegramMsg.text;
}

const historyRaw = $('Load Chat History').all();

console.log('=== LOAD HISTORY ===');
console.log('Items loaded:', historyRaw.length);

// Парсить
const historyParsed = historyRaw
  .map((item, index) => {
    try {
      const messageStr = item.json.message;
      const msg = typeof messageStr === 'string' ? JSON.parse(messageStr) : messageStr;

      if (!msg.type || !msg.content) return null;

      const role = msg.type === 'human' ? 'user' : 'assistant';

      return { role, content: msg.content.trim() };
    } catch (e) {
      console.error(`Parse error at ${index}:`, e.message);
      return null;
    }
  })
  .filter(item => item !== null && item.content);

// Убрать assistant с начала
let history = historyParsed;
while (history.length > 0 && history[0].role === 'assistant') {
  console.warn('❌ Removing leading assistant message');
  history.shift();
}

// Убрать дубли роли (user→user или assistant→assistant)
const validHistory = [];
let lastRole = null;

for (const msg of history) {
  if (msg.role === lastRole) {
    console.warn(`⚠️ Skipping duplicate ${msg.role}`);
    continue;
  }
  validHistory.push(msg);
  lastRole = msg.role;
}

const messages = [
  ...validHistory,
  { role: "user", content: userText }
];

console.log('=== FINAL ===');
console.log('Total:', messages.length);
console.log('First role:', messages[0]?.role);

// ⚠️ FINAL CHECK
if (messages[0]?.role !== 'user') {
  throw new Error(`Messages must start with user, but starts with ${messages[0]?.role}`);
}

return {
  json: {
    messages,
    chat_id: chatId,
    user_text: userText
  }
};

// Получить ответ от Claude API
const claudeResponse = $input.first().json;

// ⚠️ ПРОВЕРКА: есть ли content в ответе
if (!claudeResponse.content || claudeResponse.content.length === 0) {
  // Если ошибка от Claude — покажем её
  console.error('Claude API Error:', JSON.stringify(claudeResponse, null, 2));

  throw new Error(`Claude API returned error: ${JSON.stringify(claudeResponse)}`);
}

// Извлечь текст ответа ассистента
const assistantText = $input.first().json.content[0].input.user_answer;

// Получить данные из предыдущего шага
const previousData = $('Build Messages').first().json;
const chatId = previousData.chat_id;
const userText = previousData.user_text;

// Вернуть данные для сохранения и отправки
return {
  json: {
    chat_id: chatId,
    user_text: userText,
    assistant_text: assistantText,
    // Для отладки:
    usage: claudeResponse.usage
  }
};

const subscriptionId = $('Check Subscription').first().json.subscription_id;
const userText = $input.first().json.user_text;
const assistantText = $input.first().json.assistant_text;

// Подготовить два сообщения для INSERT
const userMessage = {
  subscription_id: subscriptionId,
  message: JSON.stringify({
    type: "human",
    content: userText
  })
};

const aiMessage = {
  subscription_id: subscriptionId,
  message: JSON.stringify({
    type: "ai",
    content: assistantText
  })
};

// Вернуть оба сообщения для Postgres
return [
  { json: userMessage },
  { json: aiMessage }
];

for (const item of $input.all()) {
  if (item.json.remaining_week <= 0)
    return {
      available: false,
      limit_window: '7 days',
    };

  if (item.json.remaining_day <= 0)
    return {
      available: false,
      limit_window: '1 day',
    };

  if (item.json.remaining_4h <= 0)
    return {
      available: false,
      limit_window: '4 hours',
    };

  return {
    available: true,
    limit_window: '',
  };
}

