SELECT requested_at + INTERVAL '{{ $('Check Request Limits').item.json.limit_window }}' - now() AS retry_after
  FROM request_log
  WHERE subscription_id = (
  SELECT id FROM subscriptions WHERE user_id = (
  SELECT id FROM users WHERE telegram_id = {{ $('Telegram User Message').first().json.message.chat.id }}
LIMIT 1
  )
  AND is_active = TRUE
  LIMIT 1
  )
  AND requested_at >= now() - INTERVAL '{{ $('Check Request Limits').item.json.limit_window }}'
  ORDER BY requested_at ASC
  LIMIT 1;

