var limitWindow = $('Check Request Limits').first().json.limit_window;
var windowText = '';

switch (limitWindow) {
  case '7 days':
    windowText = ' неделю';
    break;
  case '1 day':
    windowText = ' сутки';
    break;
  case '4 hours':
  default:
    windowText = ' 4 часа';
    break;
}

var message = "Вы достигли лимита запросов в" + windowText + ". Пожалуйста, попробуйте снова через";

var retryAfter = $input.first().json.retry_after;

if (retryAfter.days)
  message += " " + retryAfter.days + " дней";

if (retryAfter.hours)
  message += " " + retryAfter.hours + " часа";

if (retryAfter.minutes)
  message += " " + retryAfter.minutes + " минут";

if (retryAfter.seconds)
  message += " " + retryAfter.seconds + " секунд";

return { message: message };
